export function toDb( fieldsMap, type, data, options = {} ) {

  return fieldsMap.reduce( ( result, field ) => {

    if ( [ 'insert', 'update' ].includes( type ) ) {

      if ( field.protected && options.protected ) {
        return result;
      }

    } else if ( [ 'select' ].includes( type ) ) {

      if ( field.internal && !options.internal ) {
        return result;
      }

    }

    const value = data[ field.obj ];

    if ( value === undefined ) {
      return result;
    }

    result[ field.db ] = field.json ? JSON.stringify( value ) : value;

    return result;

  }, {} );

}

export function listFields( fieldsMap, from = 'db', type, options = {} ) {

  return filter( fieldsMap, type, options )
    .map( field => field[ from ] );

}

function filter( fieldsMap, type, options = {} ) {

  return fieldsMap.filter( field => {

    if ( [ 'insert', 'update' ].includes( type ) ) {

      if ( field.protected && options.protected ) {
        return false;
      }

    } else if ( [ 'select' ].includes( type ) ) {

      if ( field.internal && !options.internal ) {
        return false;
      }

    }

    return true;

  } );

}
